mapper.select:
SELECT * FROM coach_health_fitness 
WHERE coach_id = #{coachId} 
ORDER BY record_date DESC 
LIMIT #{limit}

mapper.update:
UPDATE coach_health_fitness
weight = #{weight}, body_fat_rate = #{bodyFatRate}, heart_rate = #{heartRate}, training_hours = #{trainingHours}, calories_burned = #{caloriesBurned}, muscle_mass = #{muscleMass}, bmi = #{bmi}, strength_score = #{strengthScore}, endurance_score = #{enduranceScore}, flexibility_score = #{flexibilityScore}, speed_score = #{speedScore}, coordination_score = #{coordinationScore},
WHERE id = #{id}
